import React, { useState, useEffect } from "react";
import "../styles/GeneralChat.css";

const therapistReplies = [
  "I’m really glad you shared this 💜",
  "That sounds emotionally heavy. I’m here with you.",
  "Take your time — there’s no rush.",
  "Would you like to tell me more about what’s been weighing on you?",
  "You’re not alone. I’m listening."
];

export default function GeneralChat() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);

  useEffect(() => {
    setMessages([
      {
        sender: "bot",
        text: "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?"
      }
    ]);
  }, []);

  const sendMessage = () => {
    if (!input.trim()) return;

    const userMsg = { sender: "user", text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput("");
    setTyping(true);

    setTimeout(() => {
      const reply =
        therapistReplies[Math.floor(Math.random() * therapistReplies.length)];

      setMessages(prev => [
        ...prev,
        { sender: "bot", text: reply }
      ]);
      setTyping(false);
    }, 1500);
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        🧠 General Chat
        <div className="listening-badge">💗 Listening</div>
      </div>

      <div className="chat-body">
        {messages.map((msg, i) => (
          <div
            key={i}
            className={`message ${msg.sender === "user" ? "user-msg" : "bot-msg"}`}
          >
            <div className="message-bubble">{msg.text}</div>
          </div>
        ))}

        {typing && (
          <div className="message bot-msg">
            <div className="typing-indicator">
              <span></span><span></span><span></span>
            </div>
          </div>
        )}
      </div>

      <div className="chat-input">
        <input
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => e.key === "Enter" && sendMessage()}
          placeholder="Type how you feel..."
        />
        <button onClick={sendMessage}>Send</button>
      </div>
    </div>
  );
}
